"""
Unified interface ke berbagai LLM API — v2.5
Semua return format sama:
{
  "content": "<text dari model>",
  "tool_calls": [{"id": "...", "name": "...", "arguments": {...}}],
  "usage": {"input": N, "output": N, "total": N}
}

Support: Groq, Claude, OpenAI, MiMo, Custom (OpenAI-compatible)
Retry + backoff untuk rate limit & server error.
"""
import json
import time
import requests
import config


class BaseProvider:
    name = "base"
    model = "unknown"
    context_window = 128_000

    def chat(self, messages, tools):
        raise NotImplementedError


CONTEXT_WINDOWS = {
    "llama-3.3-70b-versatile": 128_000,
    "claude-sonnet-4-6": 200_000,
    "gpt-4o-mini": 128_000,
    "mimo-v2.5": 1_000_000,
    "mimo": 1_000_000,
}

RETRYABLE_STATUS = {429, 500, 502, 503, 529}
MAX_RETRIES = 4
BASE_BACKOFF = 2


def _request_with_retry(method, url, **kwargs):
    """Wrapper requests dengan retry+backoff untuk status retryable."""
    last_exc = None
    for attempt in range(MAX_RETRIES + 1):
        try:
            resp = method(url, **kwargs)
        except requests.exceptions.RequestException as e:
            last_exc = e
            if attempt == MAX_RETRIES:
                raise
            time.sleep(BASE_BACKOFF * (2 ** attempt))
            continue

        if resp.status_code in RETRYABLE_STATUS and attempt < MAX_RETRIES:
            wait = BASE_BACKOFF * (2 ** attempt)
            retry_after = resp.headers.get("retry-after")
            if retry_after:
                try:
                    wait = max(wait, float(retry_after))
                except ValueError:
                    pass
            time.sleep(wait)
            continue

        return resp

    if last_exc:
        raise last_exc
    return resp


class OpenAICompatProvider(BaseProvider):
    """Dipakai untuk Groq, OpenAI, MiMo, atau LLM OpenAI-compatible lainnya."""

    def __init__(self, api_key, base_url, model, name="openai-compat"):
        self.api_key = api_key
        self.base_url = base_url.rstrip("/")
        self.model = model
        self.name = name
        self.context_window = CONTEXT_WINDOWS.get(model, 128_000)

    def chat(self, messages, tools):
        resp = _request_with_retry(
            requests.post,
            f"{self.base_url}/chat/completions",
            headers={
                "Authorization": f"Bearer {self.api_key}",
                "Content-Type": "application/json",
            },
            json={
                "model": self.model,
                "messages": messages,
                "tools": tools,
                "tool_choice": "auto",
                "max_tokens": 4096,
            },
            timeout=90,
        )
        resp.raise_for_status()
        data = resp.json()
        msg = data["choices"][0]["message"]
        tool_calls = []
        for tc in msg.get("tool_calls") or []:
            tool_calls.append({
                "id": tc["id"],
                "name": tc["function"]["name"],
                "arguments": json.loads(tc["function"]["arguments"] or "{}"),
            })
        u = data.get("usage", {}) or {}
        usage = {
            "input": u.get("prompt_tokens", 0),
            "output": u.get("completion_tokens", 0),
            "total": u.get("total_tokens", 0),
        }
        return {
            "content": msg.get("content") or "",
            "tool_calls": tool_calls,
            "usage": usage,
        }


