def cleanup_pycache():
    """Hapus semua __pycache__."""
    count = 0
    for root, dirs, files in os.walk(BASE_DIR):
        if "__pycache__" in root:
            for f in files:
                os.remove(os.path.join(root, f))
                count += 1
            os.rmdir(root)
    return count


